import React from "react";
import { NavLink } from "react-router-dom";

const navItems = [
  { id: "dashboard", label: "Dashboard", dot: "#22c55e", adminOnly: false },
  { id: "needs", label: "Community Needs", dot: "#ef4444", adminOnly: false },
  { id: "volunteers", label: "Volunteers", dot: "#3b82f6", adminOnly: true },
  { id: "map", label: "Map View", dot: "#8b5cf6", adminOnly: false },
  { id: "matching", label: "Smart Match", dot: "#f59e0b", adminOnly: true },
  { id: "submit-need", label: "Submit Need", dot: "#10b981", adminOnly: false },
  { id: "add-volunteer", label: "Add Volunteer", dot: "#06b6d4", adminOnly: false },
  { id: "profile", label: "My Profile", dot: "#a855f7", volunteerOnly: true },
];

export default function Sidebar({ user, urgentCount, availableCount }) {
  const isAdmin = user?.role === "admin";
  const dashboardPath = isAdmin ? "/admin-dashboard" : "/volunteer-dashboard";

  return (
    <nav className="sidebar">
      <div className="logo">
        <h1>ReliefLink</h1>
        <p>Smart Resource Coordination</p>
      </div>
      <div className="nav-section">
        <div className="nav-label">Navigation</div>
        {navItems.map((item) => {
          if (item.adminOnly && !isAdmin) return null;
          if (item.volunteerOnly && isAdmin) return null;

          const path = item.id === "dashboard" ? dashboardPath : `/${item.id}`;

          return (
            <NavLink
              key={item.id}
              to={path}
              className={({ isActive }) => `nav-item ${isActive ? "active" : ""}`}
            >
              <span className="nav-dot" style={{ background: item.dot }} />
              {item.label}
            </NavLink>
          );
        })}
      </div>
      <div className="sidebar-footer">
        {urgentCount > 0 && (
          <div style={{ color: "#dc2626", fontWeight: 600, marginBottom: 4, fontSize: 12 }}>
            ⚠ {urgentCount} urgent needs
          </div>
        )}
        <div style={{ fontSize: 11, color: "#94a3b8" }}>{availableCount} volunteers available</div>
      </div>
    </nav>
  );
}
